import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testGetDelimiter_Default() {
        CSVFormat format = CSVFormat.DEFAULT;
        assertEquals(',', format.getDelimiter());
    }

    @Test
    void testGetDelimiter_RFC4180() {
        CSVFormat format = CSVFormat.RFC4180;
        assertEquals(',', format.getDelimiter());
    }

    @Test
    void testGetDelimiter_EXCEL() {
        CSVFormat format = CSVFormat.EXCEL;
        assertEquals(',', format.getDelimiter());
    }

    @Test
    void testGetDelimiter_TDF() {
        CSVFormat format = CSVFormat.TDF;
        assertEquals('\t', format.getDelimiter());
    }

    @Test
    void testGetDelimiter_MYSQL() {
        CSVFormat format = CSVFormat.MYSQL;
        assertEquals('\t', format.getDelimiter());
    }

    @Test
    void testGetDelimiter_NewFormat() {
        CSVFormat format = CSVFormat.newFormat(';');
        assertEquals(';', format.getDelimiter());
    }

    @Test
    void testGetDelimiter_WithDelimiter() {
        CSVFormat format = CSVFormat.DEFAULT.withDelimiter('|');
        assertEquals('|', format.getDelimiter());
    }

    @Test
    void testGetDelimiter_Reflection_PrivateField() throws Exception {
        // Use reflection to create an instance with private constructor and access private field
        var constructor = CSVFormat.class.getDeclaredConstructor(char.class, Character.class,
                CSVFormat.Quote.class, Character.class, Character.class, boolean.class,
                boolean.class, String.class, String.class, String[].class, boolean.class);
        constructor.setAccessible(true);
        CSVFormat instance = constructor.newInstance(';', null, null, null, null,
                false, false, null, null, null, false);

        var method = CSVFormat.class.getDeclaredMethod("getDelimiter");
        method.setAccessible(true);
        char delimiter = (char) method.invoke(instance);

        assertEquals(';', delimiter);
    }
}
